// ============================================
// ENERGY BAR CHART - Helpers Configuration
// ============================================

const dataFrame = context.dataFrame;

// Extrai valores de energia
let maxValue = 100;
let dataLength = 0;

if (dataFrame && dataFrame.fields) {
  const energyField = dataFrame.fields.find(f => f.name === 'energy_mwh');
  if (energyField && energyField.values) {
    const values = energyField.values.filter(v => v !== null && v !== undefined);
    dataLength = values.length;
    if (values.length > 0) {
      maxValue = Math.max(...values);
    }
  }
}

// Calcula escala do eixo Y (arredonda para múltiplo de 100)
const roundTo = 100;
const maxScale = Math.max(Math.ceil(maxValue / roundTo) * roundTo, roundTo);
const ySteps = Math.min(maxScale / roundTo, 5); // máximo 5 divisões
const yInterval = maxScale / ySteps;

// Gera array de labels do eixo Y (de cima para baixo)
const yLabels = [];
for (let i = maxScale; i >= 0; i -= yInterval) {
  yLabels.push(Math.round(i));
}
context.yLabels = yLabels;

// Gera posições das linhas de grade (em porcentagem)
const gridLines = [];
for (let i = 1; i < ySteps; i++) {
  gridLines.push(Math.round((i / ySteps) * 100));
}
context.gridLines = gridLines;

// Helper: calcula altura da barra em porcentagem
context.handlebars.registerHelper('barPct', (value) => {
  if (value === null || value === undefined || value === 0) return 2;
  const pct = (value / maxScale) * 100;
  return Math.max(pct, 2).toFixed(1);
});

// Helper: decide se mostra label do eixo X
// Mostra: primeiro, último, e a cada N intervalos
context.handlebars.registerHelper('xLabel', (index, label) => {
  const total = dataLength;
  if (total <= 10) return label; // poucos dados, mostra todos

  const interval = Math.ceil(total / 7); // ~7 labels visíveis
  const isFirst = index === 0;
  const isLast = index === total - 1;
  const isInterval = index % interval === 0;

  return (isFirst || isLast || isInterval) ? label : '';
});

// ===========================================
// PLANTS TABLE - Helpers
// ===========================================

// Retorna a cor inline baseado no status
context.handlebars.registerHelper('rowColor', function(status, inverterPct) {
  if (status === 'critical') return '#f85149';
  if (status === 'acknowledged') return '#f0883e';
  if (status === 'no_communication') return '#8b949e';
  if (status === 'generating' && inverterPct < 100) return '#d29922';
  if (status === 'generating') return '#3fb950';
  return '#e6edf3';
});

// Retorna o filtro CSS para o ícone
context.handlebars.registerHelper('iconFilter', function(status, inverterPct) {
  if (status === 'critical') return 'filter: brightness(0) saturate(100%) invert(47%) sepia(94%) saturate(3506%) hue-rotate(336deg) brightness(100%) contrast(94%);';
  if (status === 'acknowledged') return 'filter: brightness(0) saturate(100%) invert(65%) sepia(85%) saturate(1500%) hue-rotate(360deg) brightness(100%) contrast(100%);';
  if (status === 'no_communication') return 'filter: grayscale(100%) brightness(60%);';
  if (status === 'generating' && inverterPct < 100) return 'filter: brightness(0) saturate(100%) invert(65%) sepia(85%) saturate(1500%) hue-rotate(360deg) brightness(100%) contrast(100%);';
  if (status === 'generating') return 'filter: brightness(0) saturate(100%) invert(73%) sepia(55%) saturate(459%) hue-rotate(82deg) brightness(95%) contrast(88%);';
  return '';
});

// Label do status
context.handlebars.registerHelper('statusLabel', function(status, inverterPct) {
  if (status === 'critical') return 'CRITICAL';
  if (status === 'acknowledged') return 'ACKNOWLEDGED';
  if (status === 'no_communication') return 'NO COMM';
  if (status === 'generating') return 'GENERATING';
  return status ? status.toUpperCase() : '';
});

// Mostra alarme apenas para critical e acknowledged
context.handlebars.registerHelper('showAlarm', function(status, alarmTime) {
  if (status === 'critical' || status === 'acknowledged') {
    return alarmTime || '';
  }
  return '';
});

// Mostra urgência apenas para critical e acknowledged
context.handlebars.registerHelper('showUrgency', function(status, urgency) {
  if (status === 'critical' || status === 'acknowledged') {
    return urgency || '';
  }
  return '';
});
